import React, { useState, useEffect } from 'react';
import { useNavigate, Link } from 'react-router-dom';
import { useDoctorRegistration } from '../../context/DoctorRegistrationContext';
import PublicLayout from '../../components/layouts/publiclayout';
import StepIndicator from '../../components/common/StepIndicator';
import DoctorPersonalForm from '../../components/forms/DoctorPersonalForm';
import '../../styles/doctor-registration.css';

const DoctorRegisterStep1: React.FC = () => {
    const navigate = useNavigate();
    const { updatePersonalData, registrationData } = useDoctorRegistration();
    const [isLoading, setIsLoading] = useState(false);

    // Load saved data if exists
    useEffect(() => {
        const savedData = localStorage.getItem('doctorPersonalData');
        if (savedData) {
            // Data will be loaded by the form component
            console.log('Loaded saved personal data');
        }
    }, []);

    const handleSubmit = async (formData: any) => {
        setIsLoading(true);

        try {
            // Update registration context
            updatePersonalData(formData);

            // Simulate API call
            await new Promise(resolve => setTimeout(resolve, 1000));

            // Navigate to next step
            navigate('/doctor/register/step2');
        } catch (error) {
            console.error('Error saving personal data:', error);
            alert('An error occurred. Please try again.');
        } finally {
            setIsLoading(false);
        }
    };

    const handleBack = () => {
        navigate('/');
    };

    const steps = [
        { number: 1, label: 'Personal Info' },
        { number: 2, label: 'Professional Info' },
        { number: 3, label: 'Verification' }
    ];

    return (
        <PublicLayout>
            <main className="main-content">
                <div className="container">
                    <div className="registration-wrapper">
                        <StepIndicator 
                            currentStep={1} 
                            steps={steps}
                        />

                        <div className="form-container">
                            <div className="form-header">
                                <h1>Doctor Registration</h1>
                                <p>Step 1: Fill in your personal information</p>
                            </div>

                            <DoctorPersonalForm 
                                onSubmit={handleSubmit}
                                isLoading={isLoading}
                                initialData={registrationData?.personal}
                                onBack={handleBack}
                            />
                        </div>
                    </div>
                </div>
            </main>
        </PublicLayout>
    );
};

export default DoctorRegisterStep1;
